    #[test]
    fn test_valid_transition() {
        let mut sm = MFADeviceStateMachine::from_state(MFADeviceState::Pending);
        assert!(sm.can_transition(MFADeviceTransition::Verify));
        let result = sm.transition(MFADeviceTransition::Verify);
        assert!(result.is_ok());
        assert_eq!(sm.current_state(), MFADeviceState::Active);
    }

    #[test]
